const _ = require('lodash');
const db = require('../../db');

/**
 * Fetch problems with optional filters for difficulty, tags, limit, and offset.
 * Supports filtering by skill tags (case-insensitive, comma-separated or array).
 * Returns problems sorted by stable criteria and metadata including normalized tags.
 *
 * @param {Object} params
 * @param {string|Array<string>} [params.tags] - Skill tags to filter by (case-insensitive).
 * @param {string} [params.difficulty] - Difficulty filter.
 * @param {number} [params.limit] - Max number of problems to return.
 * @param {number} [params.offset] - Offset for pagination.
 * @returns {Promise<{problems: Array, metadata: Object}>}
 */
async function getProblems({ tags, difficulty, limit = 50, offset = 0 } = {}) {
  // Normalize tags input to array of lowercase trimmed strings
  let normalizedTags = [];
  if (tags) {
    if (typeof tags === 'string') {
      normalizedTags = tags.split(',').map(t => t.trim().toLowerCase()).filter(t => t.length > 0);
    } else if (Array.isArray(tags)) {
      normalizedTags = tags.map(t => String(t).trim().toLowerCase()).filter(t => t.length > 0);
    }
  }

  // Base query
  let query = db('problems').select('*');

  // Filter by difficulty if provided
  if (difficulty) {
    query = query.where('difficulty', difficulty);
  }

  // Filter by tags if provided
  if (normalizedTags.length > 0) {
    // We assume problems have a 'tags' column which is an array or JSON array of tags
    // We filter problems that have all the requested tags (AND semantics)
    // Using PostgreSQL array containment operator @>
    query = query.whereRaw(
      'LOWER(tags::text) LIKE ANY (ARRAY[' +
        normalizedTags.map(() => '?').join(',') +
      '])',
      normalizedTags.map(t => `%"${t}"%`)
    );

    // Note: The above is a workaround for case-insensitive tag filtering in JSON array.
    // A more precise approach requires unnesting tags and filtering with intersection.
    // For simplicity and performance, we do a LIKE ANY on JSON text representation.
  }

  // Stable sorting: by difficulty asc, then by problemId asc
  query = query.orderBy('difficulty', 'asc').orderBy('problemId', 'asc');

  // Pagination
  query = query.limit(limit).offset(offset);

  // Execute query
  const problems = await query;

  // Prepare metadata
  const metadata = {
    count: problems.length,
    limit,
    offset,
    difficulty: difficulty || null,
    tags: normalizedTags.length > 0 ? normalizedTags : null
  };

  return { problems, metadata };
}

module.exports = {
  getProblems
};
